import { Type } from './Type.js';
/** Maps a database INTEGER/INT column to a JS `number`. */
export class IntegerType extends Type {
    getColumnType(prop, platform) {
        return platform.getIntegerTypeDeclarationSQL(prop);
    }
    compareAsType() {
        return 'number';
    }
    ensureComparable() {
        return false;
    }
}
